package main

import (
	"fmt"
	"strconv"
	"strings"
)

func main() {
	var n int
	fmt.Scan(&n)
	var parts []string
	for d := 2; d*d <= n; d++ {
		for n%d == 0 {
			parts = append(parts, strconv.Itoa(d))
			n /= d
		}
	}
	if n > 1 {
		parts = append(parts, strconv.Itoa(n))
	}
	fmt.Println(strings.Join(parts, " "))
}
